<div class="fr">
<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Indice de Choppiness : Même Mouvement, Distance Différente</text>
  <text x="20" y="50" fill="#a1a1aa" font-size="13" font-family="sans-serif">Scénario illustratif · pas des données de prix réelles · à but explicatif uniquement</text>
  <line x1="350" y1="70" x2="350" y2="355" stroke="rgba(255,255,255,.12)"/>
  <line x1="40" y1="355" x2="660" y2="355" stroke="rgba(255,255,255,.15)"/>
